import {
  existsSync,
  mkdirSync,
  readFileSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import {dirname, resolve} from 'node:path';
import {fileURLToPath} from 'node:url';
import ts from 'typescript';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, '..', '..');
const sourcePath = resolve(repoRoot, 'response-review/web/app.ts');
const outputPath = resolve(repoRoot, 'response-review/web/app.js');
const generatedHeader =
  '// Generated from response-review/web/app.ts. Do not edit this file directly.\n';

export function getResponseReviewWebBundlePaths() {
  return {
    repoRoot,
    sourcePath,
    outputPath,
  };
}

export function transpileResponseReviewWebSource(source) {
  const transpiled = ts.transpileModule(source, {
    compilerOptions: {
      target: ts.ScriptTarget.ES2022,
      module: ts.ModuleKind.None,
      newLine: ts.NewLineKind.LineFeed,
      removeComments: false,
    },
    fileName: sourcePath,
  });

  return `${generatedHeader}${transpiled.outputText}`;
}

export function buildResponseReviewWebBundle() {
  const source = readFileSync(sourcePath, 'utf8');
  const output = transpileResponseReviewWebSource(source);
  mkdirSync(dirname(outputPath), {recursive: true});
  writeFileSync(outputPath, output, 'utf8');
  return getResponseReviewWebBundlePaths();
}

export function ensureResponseReviewWebBundle(options = {}) {
  const rebuildIfStale = options.rebuildIfStale === true;

  if (!existsSync(outputPath)) {
    return buildResponseReviewWebBundle();
  }

  if (rebuildIfStale) {
    const sourceStat = statSync(sourcePath);
    const outputStat = statSync(outputPath);
    if (sourceStat.mtimeMs > outputStat.mtimeMs) {
      return buildResponseReviewWebBundle();
    }
  }

  return getResponseReviewWebBundlePaths();
}
